import React, { useState } from 'react';

const campos = [
  'Ano',
  'Nome da Estação',
  'Tipo de Estação',
  'Endereço',
  'Município',
  'UF',
  'Latitude',
  'Longitude',
  'Status',
  'Data de Ativação',
  'Data de Desativação',
  'Responsável Técnico',
  'Contato',
  'Observações'
];

export default function EstacoesInfra() {
  const [valores, setValores] = useState(Array(campos.length).fill(''));

  const handleChange = (idx, value) => {
    setValores(v => {
      const novo = [...v];
      novo[idx] = value;
      return novo;
    });
  };

  const handleSubmit = e => {
    e.preventDefault();
    alert('Dados enviados!');
    // Aqui você pode enviar os dados para o backend
  };

  return (
    <form onSubmit={handleSubmit} style={{maxWidth:500, margin:'0 auto', background:'#fff', padding:24, borderRadius:8, boxShadow:'0 2px 8px #0001'}}>
      <h2 style={{marginBottom:24}}>Cadastro de Estações</h2>
      {campos.map((campo, idx) => (
        <div key={campo} style={{marginBottom:16}}>
          <label style={{
            display:'block',
            fontWeight: (idx === 0 || campo === 'Nome da Estação') ? 700 : 500,
            marginBottom:4,
            color: idx === 0 ? '#111' : undefined
          }}>{campo}</label>
          {idx === 0 ? (
            <select
              value={valores[0]}
              onChange={e => handleChange(0, e.target.value)}
              style={{
                width:'100%',
                padding:8,
                borderRadius:4,
                border:'1px solid #ccc',
                fontWeight:400,
                fontSize:16,
                background:'#f3f6fa',
                color:'#222',
                boxShadow:'none',
                letterSpacing:0
              }}
            >
              <option value="">Selecione o ano</option>
              <option value="2024">2024</option>
              <option value="2025">2025</option>
              <option value="2026">2026</option>
            </select>
          ) : (
            <input
              type="text"
              value={valores[idx]}
              onChange={e => handleChange(idx, e.target.value)}
              style={{
                width:'100%',
                padding:8,
                borderRadius:4,
                border:'1px solid #ccc',
                fontWeight:400,
                fontSize:15,
                background:'#fff',
                color:'#222'
              }}
            />
          )}
        </div>
      ))}
      <button type="submit" style={{marginTop:16, padding:'10px 24px', background:'#1976d2', color:'#fff', border:'none', borderRadius:4, fontWeight:600, fontSize:16, cursor:'pointer'}}>Salvar</button>
    </form>
  );
}
